export const SocialLinksSchema = () =>
  // Add a more specific error message to help people migrate from the old object syntax.
  // TODO: remove once most people have updated to v0.33 or higher (e.g. when releasing Starlight v1)
  z.preprocess((value, ctx) => {
    if (value && typeof value === 'object' && !Array.isArray(value)) {
      ctx.issues.push({
        code: 'custom',
        message:
          'Theme v4.1.5 changed the `social` configuration syntax. Please specify an array of link items instead of an object.',
        input: value
      })
    }
    return value
  }, LinksSchema) as unknown as typeof LinksSchema

export const GET = async () => {
	const posts = await getAllPosts();

	return rss({
		title: siteConfig.title,
		description: siteConfig.description,
		site: import.meta.env.SITE,
		items: posts.map((post) => ({
			title: post.data.title,
			description: post.data.description,
			pubDate: post.data.publishDate,
			link: `posts/${post.id}/`,
		})),
	});
};

import { toString as mdastToString } from "mdast-util-to-string";
import getReadingTime from "reading-time";

export function remarkReadingTime() {
	// @ts-expect-error:next-line
	return (tree, { data }) => {
		const textOnPage = mdastToString(tree);
		const readingTime = getReadingTime(textOnPage);
		data.astro.frontmatter.readingTime = readingTime.text;
	};
}

export function isPage(file: URL, settings: AstroSettings): boolean {
	if (!isInPagesDir(file, settings.config) && !isInjectedRoute(file, settings)) return false;
	if (!isPublicRoute(file, settings.config)) return false;
	return endsWithPageExt(file, settings);
}

export function isEndpoint(file: URL, settings: AstroSettings): boolean {
	if (!isInPagesDir(file, settings.config) && !isInjectedRoute(file, settings)) return false;
	if (!isPublicRoute(file, settings.config)) return false;
	return !endsWithPageExt(file, settings) && !file.toString().includes('?astro');
}

function getSidebarCurrentEntry(sidebar: SidebarEntry[], pathname: string): SidebarLink | null {
	for (const entry of sidebar) {
		if (entry.type === 'link' && pathsMatch(encodeURI(entry.href), pathname)) {
			return entry;
		}

		if (entry.type === 'group') {
			const currentEntry = getSidebarCurrentEntry(entry.entries, pathname);
			if (currentEntry) return currentEntry;
		}
	}
	return null;
}

export function readCache(title: string, pubDate: Date): Buffer | null {
	checkCacheDirExists();

	const cacheKey = getCacheKey(title, pubDate);
	const cacheFilePath = path.join(CACHE_DIR, `${cacheKey}.png`);

	if (fs.existsSync(cacheFilePath)) {
		console.info(`Found cached OG image for: ${title}`);
		return fs.readFileSync(cacheFilePath);
	}

	return null;
}

return Object.fromEntries(
  str.split(' ').reduce(
    (acc: [string, string | true][], cur) => {
      const matched = cur.match(/(.+)?=("(.+)"|'(.+)')$/)
      if (matched === null) return acc
      const key = matched[1]
      const value = matched[3] || matched[4] || true
      acc.push([key, value])
      return acc
    },
    [] as [string, string | true][]
  )
)

