export const UserConfigSchema = ThemeConfigSchema()
  .strict()
  .extend({
    integ: IntegrationConfigSchema()
  })
  .transform((config) => ({
    ...config,
    // Pagefind only defaults to true if prerender is also true.
    integ: {
      ...config.integ,
      pagefind: config.integ.pagefind ?? config.prerender
    }
  }))
  .refine((config) => !(config.integ.pagefind && !config.prerender), {
    message: 'Pagefind search is not supported with prerendering disabled.'
  })

function getIntermediateSidebarFromConfig(
	sidebarConfig: StarlightConfig['sidebar'],
	locale: string | undefined
): SidebarEntry[] {
	const routes = getLocaleRoutes(locale);
	if (sidebarConfig) {
		return sidebarConfig.flatMap((group) => configItemToEntry(group, locale, routes));
	} else {
		const tree = treeify(routes, locale, locale || '');
		return sidebarFromDir(tree, { collapsed: false, attrs: undefined });
	}
}

export function getOgImageUrl(path: string, isFallback: boolean): string | undefined {
	let imagePath = path.replace(/^\//, '').replace(/\/$/, '') + '.webp';
	if (isFallback) {
		// Replace the language segment with 'en' for fallback pages.
		imagePath = 'en' + imagePath.slice(imagePath.indexOf('/'));
	}
	if (paths.has(imagePath)) return '/open-graph/' + imagePath;
}
